 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import InlineFilterSelect from '@kubevirt-utils/components/FilterSelect/InlineFilterSelect';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { modelToGroupVersionKind, StorageClassModel } from '@kubevirt-utils/models';
 6	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Stack, StackItem, Text, TextVariants, Title } from '@patternfly/react-core';
 8	
 9	type VirtualMachineMigrationDestinationTabProps = {
10	  defaultStorageClassName: string;
11	  destinationStorageClass: string;
12	  setSelectedStorageClass: Dispatch<SetStateAction<string>>;
13	  sortedStorageClasses: string[];
14	};
15	
16	const StorageClassModelGroupVersionKind = modelToGroupVersionKind(StorageClassModel);
17	
18	const VirtualMachineMigrationDestinationTab: FC<VirtualMachineMigrationDestinationTabProps> = ({
19	  defaultStorageClassName,
20	  destinationStorageClass,
21	  setSelectedStorageClass,
22	  sortedStorageClasses,
23	}) => {
24	  const { t } = useKubevirtTranslation();
25	  return (
26	    <Stack hasGutter>
27	      <StackItem>
28	        <Title headingLevel="h2">{t('Destination StorageClass')}</Title>
29	        <Text component={TextVariants.p}>
30	          {t('Select the destination storage for the VirtualMachine storage migration.')}
31	        </Text>
32	      </StackItem>
33	      <StackItem>
34	        <InlineFilterSelect
35	          options={sortedStorageClasses?.map((storageClass) => ({
36	            children: (
37	              <>
38	                <ResourceLink
39	                  groupVersionKind={StorageClassModelGroupVersionKind}
40	                  inline
41	                  linkTo={false}
42	                  name={storageClass}
43	                />
44	                {defaultStorageClassName === storageClass ? t('(default)') : ''}
45	              </>
46	            ),
47	            value: storageClass,
48	          }))}
49	          popperProps={{
50	            appendTo: () => document.getElementById('virtual-machine-migration-modal'),
51	          }}
52	          selected={destinationStorageClass}
53	          setSelected={setSelectedStorageClass}
54	          toggleProps={{ isFullWidth: true, placeholder: t('Select StorageClass') }}
55	        />
56	      </StackItem>
57	    </Stack>
58	  );
59	};
60	
61	export default VirtualMachineMigrationDestinationTab;

